import React, { useState } from 'react';
import { User } from '../types';

interface AuthPageProps {
  onLogin: (email: string) => User;
}

// Quick-pick accounts for demo convenience
const DEMO_ACCOUNTS = [
  { label: 'Admin account',       email: 'admin@formthread.io',   role: 'admin' as const },
  { label: 'Arjun (participant)', email: 'arjun@nexaralabs.com',  role: 'participant' as const },
  { label: 'Sara (participant)',  email: 'sara@lind-studio.com',  role: 'participant' as const },
  { label: 'Devraj (participant)',email: 'devraj@gmail.com',       role: 'participant' as const },
];

const AuthPage: React.FC<AuthPageProps> = ({ onLogin }) => {
  const [loading, setLoading] = useState(false);
  const [selectedEmail, setSelectedEmail] = useState(DEMO_ACCOUNTS[0].email);

  const handleLogin = (email: string) => {
    setLoading(true);
    // Simulate async OAuth handshake
    setTimeout(() => {
      onLogin(email);
      setLoading(false);
    }, 800);
  };

  return (
    <div className="relative z-10 h-screen flex items-center justify-center">
      {/* Auth card */}
      <div className="w-[380px] bg-zinc-900 border border-zinc-800 rounded-sm shadow-2xl shadow-black/60">

        {/* Card header */}
        <div className="px-8 pt-8 pb-6 border-b border-zinc-800">
          <div className="flex items-center gap-2.5 mb-5">
            <div className="w-7 h-7 bg-amber-400 flex items-center justify-center text-black font-bold text-[11px] font-mono rounded-sm">
              FT
            </div>
            <span className="text-[14px] font-semibold text-zinc-100">FormThread</span>
          </div>
          <h1 className="text-[18px] font-semibold text-zinc-100 leading-snug">
            Sign in to your workspace
          </h1>
          <p className="font-mono text-[10px] text-zinc-500 mt-1.5">
            conversational forms · role-based access
          </p>
        </div>

        {/* Card body */}
        <div className="px-8 py-6 flex flex-col gap-4">

          {/* Demo account selector */}
          <div>
            <label className="font-mono text-[9px] text-zinc-500 uppercase tracking-[.1em] block mb-2">
              Demo account
            </label>
            <div className="flex flex-col gap-1">
              {DEMO_ACCOUNTS.map((acct) => (
                <button
                  key={acct.email}
                  onClick={() => setSelectedEmail(acct.email)}
                  className={`
                    w-full text-left px-3 py-2.5 rounded-sm border transition-all duration-100
                    flex items-center justify-between gap-3
                    ${selectedEmail === acct.email
                      ? 'border-amber-400/40 bg-amber-400/5'
                      : 'border-zinc-800 hover:border-zinc-700 hover:bg-zinc-800/50'
                    }
                  `}
                >
                  <div className="flex items-center gap-2.5 min-w-0">
                    <div className={`
                      w-5 h-5 rounded-sm flex items-center justify-center
                      font-mono text-[9px] font-bold flex-shrink-0
                      ${selectedEmail === acct.email ? 'bg-amber-400 text-black' : 'bg-zinc-700 text-zinc-400'}
                    `}>
                      {acct.email[0].toUpperCase()}
                    </div>
                    <div className="min-w-0">
                      <p className={`text-[11px] font-medium truncate ${selectedEmail === acct.email ? 'text-zinc-100' : 'text-zinc-400'}`}>
                        {acct.label}
                      </p>
                      <p className="font-mono text-[9px] text-zinc-600 truncate">{acct.email}</p>
                    </div>
                  </div>
                  <span className={`
                    flex-shrink-0 font-mono text-[8px] px-1.5 py-0.5 rounded-sm border
                    ${acct.role === 'admin'
                      ? 'text-amber-400 border-amber-400/30 bg-amber-400/10'
                      : 'text-zinc-500 border-zinc-700 bg-zinc-800'
                    }
                  `}>
                    {acct.role}
                  </span>
                </button>
              ))}
            </div>
          </div>

          {/* Divider */}
          <div className="flex items-center gap-3">
            <div className="flex-1 h-px bg-zinc-800" />
            <span className="font-mono text-[9px] text-zinc-700">or sign in with</span>
            <div className="flex-1 h-px bg-zinc-800" />
          </div>

          {/* Google button */}
          <button
            onClick={() => handleLogin(selectedEmail)}
            disabled={loading}
            className={`
              w-full flex items-center justify-center gap-3
              px-4 py-3 rounded-sm border transition-all duration-150
              ${loading
                ? 'border-zinc-700 bg-zinc-800 cursor-not-allowed'
                : 'border-zinc-700 bg-zinc-800/60 hover:bg-zinc-800 hover:border-zinc-600 active:scale-[.99]'
              }
            `}
          >
            {loading ? (
              <>
                <LoadingSpinner />
                <span className="font-mono text-[11px] text-zinc-400">Signing in…</span>
              </>
            ) : (
              <>
                <GoogleIcon />
                <span className="text-[12px] font-medium text-zinc-300">Continue with Google</span>
              </>
            )}
          </button>

          {/* Fine print */}
          <p className="font-mono text-[9px] text-zinc-700 text-center leading-relaxed">
            By continuing you agree to the Terms of Service.<br />
            Role is assigned based on your email address.
          </p>
        </div>
      </div>
    </div>
  );
};

// ── Inline SVG icons ──────────────────────────────────────────────────────────

const GoogleIcon = () => (
  <svg width="16" height="16" viewBox="0 0 18 18" fill="none">
    <path d="M17.64 9.2c0-.637-.057-1.251-.164-1.84H9v3.481h4.844c-.209 1.125-.843 2.078-1.796 2.717v2.258h2.908c1.702-1.567 2.684-3.875 2.684-6.615z" fill="#4285F4"/>
    <path d="M9 18c2.43 0 4.467-.806 5.956-2.184l-2.908-2.258c-.806.54-1.837.86-3.048.86-2.344 0-4.328-1.584-5.036-3.711H.957v2.332A8.997 8.997 0 009 18z" fill="#34A853"/>
    <path d="M3.964 10.707A5.41 5.41 0 013.682 9c0-.593.102-1.17.282-1.707V4.961H.957A8.996 8.996 0 000 9c0 1.452.348 2.827.957 4.039l3.007-2.332z" fill="#FBBC05"/>
    <path d="M9 3.58c1.321 0 2.508.454 3.44 1.345l2.582-2.58C13.463.891 11.426 0 9 0A8.997 8.997 0 00.957 4.96L3.964 7.293C4.672 5.163 6.656 3.58 9 3.58z" fill="#EA4335"/>
  </svg>
);

const LoadingSpinner = () => (
  <svg
    width="14" height="14" viewBox="0 0 14 14"
    className="animate-spin"
    style={{ animation: 'spin 0.8s linear infinite' }}
  >
    <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    <circle cx="7" cy="7" r="5.5" stroke="#52525b" strokeWidth="1.5" fill="none" />
    <path d="M7 1.5A5.5 5.5 0 0112.5 7" stroke="#fbbf24" strokeWidth="1.5" strokeLinecap="round" fill="none"/>
  </svg>
);

export default AuthPage;
